/*
 * Interrupt Handling Simulation
 * Demonstrates hardware interrupt handling, ISR, and interrupt enable/disable
 */

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <time.h>

// CPU State Structure
typedef struct {
 int pc; // Program Counter
 int acc; // Accumulator
 bool interrupt_enabled;
 bool interrupt_pending;
 int interrupt_vector;
} CPUState;

// I/O Device Structure
typedef struct {
 char name[20];
 bool ready;
 int data;
 bool interrupt_requested;
} IODevice;

// Interrupt Service Routine (ISR) pointers
typedef void (*ISR)();

// Global variables
CPUState cpu;
IODevice keyboard, timer;
bool global_running = true;

// Function prototypes
void initialize_system();
void fetch_decode_execute();
void check_interrupts();
void handle_interrupt(int vector);
void keyboard_isr();
void timer_isr();
void simulate_io_operation();

int main() {
 printf("========================================\n");
 printf("Interrupt Handling Simulation\n");
 printf("========================================\n\n");

 initialize_system();

 // Main program loop
 int cycle = 0;
 while (global_running && cycle < 20) {
 cycle++;
 printf("\n--- CPU Cycle %d ---", cycle);
 printf("\nPC: %d, ACC: %d, IE: %s\n", 
 cpu.pc, cpu.acc, cpu.interrupt_enabled ? "ON" : "OFF");

 // Check for pending interrupts
 check_interrupts();

 // Execute main program
 fetch_decode_execute();

 // Randomly simulate I/O events
 simulate_io_operation();

 // Small delay for demonstration
 // In real systems, this would be actual CPU execution
 }

 printf("\n========================================\n");
 printf("Simulation Complete\n");
 printf("========================================\n");

 return 0;
}

void initialize_system() {
 // Initialize CPU state
 cpu.pc = 0;
 cpu.acc = 0;
 cpu.interrupt_enabled = true;
 cpu.interrupt_pending = false;
 cpu.interrupt_vector = 0;

 // Initialize I/O devices
 strcpy(keyboard.name, "Keyboard");
 keyboard.ready = false;
 keyboard.data = 0;
 keyboard.interrupt_requested = false;

 strcpy(timer.name, "System Timer");
 timer.ready = true;
 timer.data = 100; // Tick count
 timer.interrupt_requested = false;

 printf("System initialized.\n");
 printf("CPU: PC=0, ACC=0, Interrupts ENABLED\n");
}

void check_interrupts() {
 // Check if interrupts are enabled
 if (!cpu.interrupt_enabled) {
 return;
 }

 // Check for interrupt requests from devices
 if (keyboard.interrupt_requested) {
 printf(">>> INTERRUPT REQUEST: Keyboard input ready <<<\n");
 cpu.interrupt_pending = true;
 cpu.interrupt_vector = 0x21; // Keyboard interrupt vector
 keyboard.interrupt_requested = false;
 }

 if (timer.interrupt_requested) {
 printf(">>> INTERRUPT REQUEST: Timer tick <<<\n");
 cpu.interrupt_pending = true;
 cpu.interrupt_vector = 0x20; // Timer interrupt vector
 timer.interrupt_requested = false;
 }

 // Handle pending interrupt
 if (cpu.interrupt_pending) {
 handle_interrupt(cpu.interrupt_vector);
 }
}

void handle_interrupt(int vector) {
 printf("\n!!! INTERRUPT HANDLER ACTIVATED !!!\n");
 printf("Vector: 0x%02X\n", vector);

 // Save CPU state (push to stack simulation)
 int saved_pc = cpu.pc;
 int saved_acc = cpu.acc;

 printf("Saving state: PC=%d, ACC=%d\n", saved_pc, saved_acc);

 // Disable interrupts during ISR
 cpu.interrupt_enabled = false;

 // Jump to Interrupt Service Routine
 switch (vector) {
 case 0x20:
 timer_isr();
 break;
 case 0x21:
 keyboard_isr();
 break;
 default:
 printf("Unknown interrupt vector!\n");
 }

 // Restore CPU state (pop from stack simulation)
 cpu.pc = saved_pc;
 cpu.acc = saved_acc;

 printf("Restored state: PC=%d, ACC=%d\n", cpu.pc, cpu.acc);

 // Re-enable interrupts
 cpu.interrupt_enabled = true;
 cpu.interrupt_pending = false;

 printf("Interrupt handling complete.\n");
}

void timer_isr() {
 printf(" [Timer ISR] Processing timer interrupt...\n");
 timer.data++;
 printf(" [Timer ISR] Timer tick: %d\n", timer.data);

 // Perform system tick processing
 if (timer.data % 5 == 0) {
 printf(" [Timer ISR] System maintenance tasks...\n");
 }
}

void keyboard_isr() {
 printf(" [Keyboard ISR] Processing keyboard input...\n");
 // Simulate reading keypress
 keyboard.data = 'A'; // Simulated key
 keyboard.ready = true;
 printf(" [Keyboard ISR] Key read: '%c'\n", keyboard.data);

 // Store in accumulator for main program
 cpu.acc = keyboard.data;
}

void fetch_decode_execute() {
 // Simulate main program execution
 cpu.pc++;

 // Simulate some CPU work
 cpu.acc += 1;

 // Randomly generate interrupts for demonstration
 int rand_val = rand() % 10;

 if (rand_val == 0) {
 keyboard.interrupt_requested = true;
 } else if (rand_val == 1) {
 timer.interrupt_requested = true;
 }
}

void simulate_io_operation() {
 // Simulate I/O completion that generates interrupt
 // In real systems, hardware generates this signal
}
